  ('disabled-7c4986e7-moex-00001', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-114-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '某國生產X與Y兩種財貨，A點(X , Y )=(4, 2)與B點(X , Y )=(2, 4)位 A A B B 於同一條生產可能曲線上，若該生產可能曲線向外凸出，下列何種生產組合', '["(X, Y)=(2, 2)", "(X, Y)=(3, 3)", "(X,Y)=(2.5,3.5)", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "b8525077d2fd", "answer_pdf_sha1": "4fb29f00a092", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "407", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00002', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-114-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '假設小明對接下來1小時之安排有幾種可能選項，而各選項可從中獲得滿 足或報酬及必須支付之成本如下：放空休息，享受價值400元，不用其他 成本；家教，報酬 500 元，成本 50 元；看電影，享受價值 500 元，成本 250元；工地打工，報酬800元，成本500元；其應選擇：', '["家教，其機會成本為放空休息", "家教，其機會成本為工地打工", "放空休息，其機會成本為工地打工", "工地打工，其機會成本為家教"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "b8525077d2fd", "answer_pdf_sha1": "4fb29f00a092", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "407", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00003', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-114-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '假設A國的生產力為每小時生產2條麵包或3件襯衫、B國的生產力為每 小時生產1條麵包或1件襯衫，則下列敘述何者正確？', '["A國在生產麵包上有比較利益（comparativeadvantage）", "A國在生產襯衫上有比較利益", "B國在生產麵包上有絕對利益（absoluteadvantage）", "B國在生產襯衫上有絕對利益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "b8525077d2fd", "answer_pdf_sha1": "4fb29f00a092", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "407", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00004', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-114-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '假設某一小國國內對玉米的需求函數為P=304Q，供給函數為P=6+4Q， 其中 Q 的單位為公噸、P 的單位為萬元。如果玉米的世界市場價格為每公噸 14萬元，該國將開放玉米自由貿易。下列針對貿易開放前後的敘述何者錯誤？', '["開放自由貿易之後的玉米價格為14萬元", "開放玉米自由貿易之後，國內廠商生產會減少1公噸", "開放玉米自由進口之後，進口量為1公噸", "開放玉米自由貿易之後，國內總消費量會增加1公噸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "b8525077d2fd", "answer_pdf_sha1": "4fb29f00a092", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "407", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL),
  ('disabled-7c4986e7-moex-00005', 'disabled-7c4986e7', 'disabled-7c4986e7-moex-114-6948958a', 'sub-disabled-7c4986e7-01', NULL, 'single_choice', '某財貨市場為完全競爭，供給函數為Q=P200、需求函數為Q=400P。 若政府對該財貨課徵每單位 10 元的從量稅，則此一從量稅有多少是由生 產者負擔？', '["0", "2", "5", "10"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:58+00:00", "source_pdf_sha1": "b8525077d2fd", "answer_pdf_sha1": "4fb29f00a092", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "407", "s": "0806", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "金融保險"}'::jsonb, NULL)
